<template><BaseCard><h3 class="mb-1 text-lg font-semibold">Horarios de atención</h3><p class="mb-4 text-sm text-gray-500">Estos horarios también se incorporan al contexto del asistente de WhatsApp.</p><div class="space-y-3"><div v-for="h in hours" :key="h.dayOfWeek" class="grid grid-cols-1 items-center gap-3 rounded-lg border p-3 sm:grid-cols-4"><span class="font-medium">{{ days[h.dayOfWeek] }}</span><label class="text-sm"><input v-model="h.isClosed" type="checkbox" class="mr-2">Cerrado</label><input v-model="h.openTime" type="time" :disabled="h.isClosed" class="rounded border-gray-300"><input v-model="h.closeTime" type="time" :disabled="h.isClosed" class="rounded border-gray-300"></div></div><div class="mt-4 flex justify-end"><BaseButton :loading="saving" @click="save">Guardar horarios</BaseButton></div></BaseCard></template>
<script setup lang="ts">import{onMounted,ref}from'vue';import BaseCard from '@/components/ui/BaseCard.vue';import BaseButton from '@/components/ui/BaseButton.vue';import{branchBusinessHoursApi,type BranchBusinessHour}from'@/services/MainAPI/branchBusinessHoursApi';const p=defineProps<{branchId:number}>();const days=['Domingo','Lunes','Martes','Miércoles','Jueves','Viernes','Sábado'];const hours=ref<BranchBusinessHour[]>([]),saving=ref(false);function defaults(){hours.value=days.map((_,i)=>({branchId:p.branchId,dayOfWeek:i,openTime:'08:00',closeTime:'18:00',isClosed:i===0,displayOrder:(i+6)%7}))}onMounted(async()=>{defaults();const r=await branchBusinessHoursApi.getHours(p.branchId);if(r.data.length)hours.value=r.data});async function save(){saving.value=true;try{hours.value=(await branchBusinessHoursApi.save(p.branchId,hours.value)).data}finally{saving.value=false}}</script>
